using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Orders;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    // в”Җв”Җ CreateOrder: Happy path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void CreateOrder_ValidCustomerAndItems_ReturnsOrderWithCorrectProperties()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 }
        };

        // Act
        var before = DateTime.UtcNow;
        var order = _sut.CreateOrder("cust-1", items);
        var after = DateTime.UtcNow;

        // Assert
        Assert.IsNotNull(order);
        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id), "Id should be a non-empty GUID string.");
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreSame(items, order.Items);
        Assert.AreEqual(20.00m, order.Total);
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            "CreatedAt should be between the timestamps taken before and after the call.");
    }

    [TestMethod]
    public void CreateOrder_ValidOrder_IsRetrievableByGetOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Gadget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var created = _sut.CreateOrder("cust-1", items);
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.AreSame(created, retrieved);
    }

    // в”Җв”Җ CreateOrder: Total calculation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void CreateOrder_MultipleItems_CalculatesTotalCorrectly()
    {
        // Arrange вҖ” 3 items with varying price Г— quantity
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 10.00m, Quantity = 2 },  // 20
            new() { ProductName = "B", Price = 5.50m,  Quantity = 3 },  // 16.50
            new() { ProductName = "C", Price = 100.00m, Quantity = 1 }  // 100
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert вҖ” 20 + 16.50 + 100 = 136.50
        Assert.AreEqual(136.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SingleItemQuantityOne_TotalEqualsPrice()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Solo", Price = 42.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-3", items);

        // Assert
        Assert.AreEqual(42.00m, order.Total);
    }

    // в”Җв”Җ CreateOrder: Error cases в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "X", Price = 1m, Quantity = 1 }
        };

        // Act & Assert
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // в”Җв”Җ GetOrder в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void GetOrder_ExistingOrderId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Found", Price = 7.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-10", items);

        // Act
        var result = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
        Assert.AreEqual("cust-10", result.CustomerId);
        Assert.AreEqual(7.00m, result.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentOrderId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("does-not-exist");

        // Assert
        Assert.IsNull(result);
    }

    // в”Җв”Җ GetOrdersByCustomer в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsAllTheirOrders()
    {
        // Arrange вҖ” create 2 orders for the same customer
        var items1 = new List<OrderItem> { new() { ProductName = "P1", Price = 1m, Quantity = 1 } };
        var items2 = new List<OrderItem> { new() { ProductName = "P2", Price = 2m, Quantity = 1 } };

        var order1 = _sut.CreateOrder("cust-A", items1);
        var order2 = _sut.CreateOrder("cust-A", items2);

        // Act
        var results = _sut.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.AreEqual(2, results.Count);
        CollectionAssert.Contains(results.Select(o => o.Id).ToList(), order1.Id);
        CollectionAssert.Contains(results.Select(o => o.Id).ToList(), order2.Id);
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        // Act
        var results = _sut.GetOrdersByCustomer("ghost-customer");

        // Assert
        Assert.AreEqual(0, results.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleCustomers_ReturnsOnlyMatchingCustomerOrders()
    {
        // Arrange
        var items = new List<OrderItem> { new() { ProductName = "Shared", Price = 5m, Quantity = 1 } };

        _sut.CreateOrder("cust-X", items);
        var orderY = _sut.CreateOrder("cust-Y", items);
        _sut.CreateOrder("cust-X", items);

        // Act
        var results = _sut.GetOrdersByCustomer("cust-Y");

        // Assert
        Assert.AreEqual(1, results.Count);
        Assert.AreEqual(orderY.Id, results[0].Id);
        Assert.AreEqual("cust-Y", results[0].CustomerId);
    }
}

